sql:
SELECT total_value, gain_since_inception
FROM investment_performance
ORDER BY gain_since_inception DESC;

SELECT investment_name, industry
FROM investments
ORDER BY investment_name ASC;

SELECT COUNT(*) AS active_investment_count
FROM investments
WHERE status = 'active';

SELECT COUNT(DISTINCT investment_id) AS distinct_investment_count
FROM investments
WHERE status = 'Exited' AND industry = 'Technology';

external_knowledge:
- 'Most profitable investments' refers to the investments with the highest numerical gains since inception; 
- 'Most recent gains' in this context imply the latest available gains since inception, represented by the 'gain_since_inception' column;
- 'Top three' indicates that only the top three investments based on the descending order of the gain since inception are sought after.

sql:
SELECT investment_type, COUNT(*) AS number_of_investments
FROM investments
GROUP BY investment_type;

external_knowledge:
'exited' refers to investments that are no longer active;
'top performances' are based on the highest market value and latest valuation date;
'up to three of their most valuable moments' means including the top 3 market valuations per investment.

sql:
SELECT COUNT(*) as log_count
FROM audit_logs
WHERE user_id = 0;

external_knowledge:
- "sprouted from seeds with a growth potential exceeding a decade" refers to investments with a gross IRR greater than 10%;
- "average treasure value" refers to the average current market value of the investments;
- The SQL query transforms the percentage format of gross IRR into a real number to make proper comparisons.

sql:
SELECT fund_name
FROM funds
WHERE vintage_year > 1990;

SELECT SUM(capital_committed) AS total_capital_committed
FROM capital_commitments
WHERE investment_id = 1;

SELECT AVG(current_market_value) AS average_market_value
FROM valuations
WHERE valuation_date BETWEEN date('now', '-1 year') AND date('now');

SELECT investor_name
FROM investors
WHERE investor_type = 'general partner';

SELECT AVG(total_value) AS average_total_value
FROM investment_performance
WHERE gain_since_inception IS NOT NULL AND gain_since_inception <> '';
